package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.math.BigDecimal;import java.sql.*;import java.time.*;import java.util.*;
/** Medical-record use cases with appointment-derived identities and server-side ownership. */
public class MedicalRecordServiceImpl implements MedicalRecordService {private static final Logger LOG=LoggerFactory.getLogger(MedicalRecordServiceImpl.class);private final MedicalRecordDao records;private final AppointmentDao appointments;private final DoctorDao doctors;private final PatientDao patients;private final MedicalRecordValidator validator;private final AuditLogDao audit;public MedicalRecordServiceImpl(){this(new MedicalRecordDaoImpl(),new AppointmentDaoImpl(),new DoctorDaoImpl(),new PatientDaoImpl(),new MedicalRecordValidator(),new AuditLogDaoImpl());}public MedicalRecordServiceImpl(MedicalRecordDao r,AppointmentDao a,DoctorDao d,PatientDao p,MedicalRecordValidator v,AuditLogDao l){records=r;appointments=a;doctors=d;patients=p;validator=v;audit=l;}
public Page<MedicalRecord>listRecords(PageRequest p,Long pi,Long di,Long dep,LocalDate from,LocalDate to,AuthenticatedUser u){PageRequest q=p==null?new PageRequest(1,10,""):p;try{if(u==null)return empty(q);if("DOCTOR".equals(u.getRoleName())){Doctor d=doctor(u);if(d==null)return empty(q);di=d.getDoctorId();}else if("PATIENT".equals(u.getRoleName())){Patient x=patient(u);if(x==null)return empty(q);pi=x.getPatientId();}else if(!"ADMIN".equals(u.getRoleName()))return empty(q);return records.findAll(q,pi,di,dep,from,to);}catch(SQLException e){LOG.error("Medical record listing failed",e);return empty(q);}}
public Optional<MedicalRecord>getRecord(Long id,AuthenticatedUser u){try{return records.findById(id).filter(r->canView(r,u));}catch(SQLException e){LOG.error("Medical record lookup failed",e);return Optional.empty();}}public Optional<MedicalRecord>getRecordByAppointment(Long id,AuthenticatedUser u){try{return records.findByAppointmentId(id).filter(r->canView(r,u));}catch(SQLException e){LOG.error("Medical record appointment lookup failed",e);return Optional.empty();}}
public ServiceResult<Long>createRecord(MedicalRecordForm f,AuditContext x,AuthenticatedUser u){ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Appointment a=appointments.findById(f.getAppointmentId()).orElse(null);if(a==null)return failL(ServiceResult.Status.NOT_FOUND,"Appointment not found");if(!canManage(a.getDoctorId(),u)){event("MEDICAL_RECORD_ACCESS_DENIED",null,x);return failL(ServiceResult.Status.FORBIDDEN,"Medical record access denied");}if(!Set.of("CONFIRMED","COMPLETED").contains(a.getStatus())){event("MEDICAL_RECORD_CREATION_BLOCKED",null,x);return failL(ServiceResult.Status.CONFLICT,"Only confirmed or completed appointments can receive a medical record");}if(records.existsByAppointmentId(a.getAppointmentId()))return failL(ServiceResult.Status.DUPLICATE,"A medical record already exists for this appointment");MedicalRecord r=from(f);r.setPatientId(a.getPatientId());r.setDoctorId(a.getDoctorId());r.setAppointmentId(a.getAppointmentId());r.setVisitDate(LocalDateTime.now());long id=tx(c->records.create(c,r));event("MEDICAL_RECORD_CREATED",id,x);return ServiceResult.success("Medical record created",id);}catch(SQLException e){LOG.error("Medical record creation failed",e);if(SqlExceptionUtil.isUniqueConstraintViolation(e))return failL(ServiceResult.Status.DUPLICATE,"A medical record already exists for this appointment");return failL(ServiceResult.Status.SYSTEM_ERROR,"Medical record service is temporarily unavailable");}}
public ServiceResult<Void>updateRecord(MedicalRecordForm f,AuditContext x,AuthenticatedUser u){if(f==null||f.getMedicalRecordId()==null||f.getMedicalRecordId()<=0)return fail(ServiceResult.Status.NOT_FOUND,"Medical record not found");try{MedicalRecord existing=records.findById(f.getMedicalRecordId()).orElse(null);if(existing==null)return fail(ServiceResult.Status.NOT_FOUND,"Medical record not found");if(!canManage(existing.getDoctorId(),u)){event("MEDICAL_RECORD_ACCESS_DENIED",existing.getMedicalRecordId(),x);return fail(ServiceResult.Status.FORBIDDEN,"Medical record access denied");}f.setAppointmentId(existing.getAppointmentId());ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());MedicalRecord changed=from(f);changed.setMedicalRecordId(existing.getMedicalRecordId());tx(c->{records.update(c,changed);return null;});event("MEDICAL_RECORD_UPDATED",existing.getMedicalRecordId(),x);return ServiceResult.success("Medical record updated",null);}catch(SQLException e){LOG.error("Medical record update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Medical record service is temporarily unavailable");}}
private MedicalRecord from(MedicalRecordForm f){MedicalRecord r=new MedicalRecord();r.setSymptoms(trim(f.getSymptoms()));r.setDiagnosis(trim(f.getDiagnosis()));r.setTreatmentNotes(trim(f.getTreatmentNotes()));r.setAllergies(trim(f.getAllergies()));r.setBloodPressure(trim(f.getBloodPressure()));r.setTemperature(decimal(f.getTemperature()));r.setWeight(decimal(f.getWeight()));r.setHeight(decimal(f.getHeight()));return r;}private BigDecimal decimal(String v){return v==null||v.isBlank()?null:new BigDecimal(v.trim());}private String trim(String v){return v==null?null:v.trim();}private boolean canManage(Long doctorId,AuthenticatedUser u){if(u==null)return false;if("ADMIN".equals(u.getRoleName()))return true;if(!"DOCTOR".equals(u.getRoleName()))return false;Doctor d=doctor(u);return d!=null&&d.getDoctorId().equals(doctorId);}private boolean canView(MedicalRecord r,AuthenticatedUser u){if(u==null)return false;if("ADMIN".equals(u.getRoleName()))return true;if("DOCTOR".equals(u.getRoleName())){Doctor d=doctor(u);return d!=null&&d.getDoctorId().equals(r.getDoctorId());}if("PATIENT".equals(u.getRoleName())){Patient p=patient(u);return p!=null&&p.getPatientId().equals(r.getPatientId());}return false;}private Doctor doctor(AuthenticatedUser u){try{return doctors.findByUserId(u.getUserId()).orElse(null);}catch(SQLException e){return null;}}private Patient patient(AuthenticatedUser u){try{return patients.findAll(new PageRequest(1,100,u.getUsername()),"ACTIVE").getContent().stream().filter(p->u.getUserId().equals(p.getUserId())).findFirst().orElse(null);}catch(SQLException e){return null;}}
private<T>T tx(Work<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T v=w.run(c);c.commit();return v;}catch(SQLException|RuntimeException e){c.rollback();throw e;}finally{c.setAutoCommit(old);}}}private interface Work<T>{T run(Connection c)throws SQLException;}private void event(String action,Long id,AuditContext x){try{AuditContext a=x==null?new AuditContext(null,null,null):x;audit.recordEvent(action,a.userId(),"MEDICAL_RECORD",id,a.ipAddress(),a.userAgent());}catch(RuntimeException e){LOG.warn("Medical record audit failed: {}",action,e);}}private Page<MedicalRecord>empty(PageRequest p){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}}
